<template>
    <div class="editor-wrapper">
        <div class="editor-content">
            <div class="editor-field">
                <div class="title">标题</div>
                <a-input class="text" v-model:value="editorParams.title" placeholder="请输入标题" />
            </div>
            <div class="editor-field">
                <div class="title">Tags</div>
                <a-input class="text" v-model:value="editorParams.tags" placeholder="请输入标签" />
            </div>
            <div class="editor-field editor-md-field">
                <div class="title">正文</div>
                <div class="content">
                    <v-md-editor v-model="editorParams.content" class="md-editor" @change="mdChange" :disabled-menus="[]" @copy-code-success="handleCopyCodeSuccess" @upload-image="handleUploadImage"></v-md-editor>
                </div>
            </div>
            <div class="btns">
                <a-button style="margin-right:16px" @click="cancelEditor()">取消</a-button>
                <a-button type="primary" @click="saveEdit(true)">确认</a-button>
            </div>
        </div>
    </div>
</template>
<script>
import { inject, reactive, onMounted, watchEffect, onUnmounted } from "vue";
import { useStore } from "vuex";
import { useRouter } from "vue-router";
import { message } from "ant-design-vue";

export default {
    setup() {
        const router = useRouter();
        const store = useStore();
        const $api = inject("$api");

        let editorParams = reactive({
            title: null,
            content: "",
            html: null,
            tags: null,
            imageFileIds: []
        });

        let autoSaveTimer = reactive(null);

        const mdChange = (text, htmlValue) => {
            editorParams.html = htmlValue;
        };

        // 代码复制
        const handleCopyCodeSuccess = () => {
            message.success("代码已复制");
        };

        // 上传图片
        const handleUploadImage = (event, insertImage, files) => {
            // 拿到 files 之后上传到文件服务器，然后向编辑框中插入对应的内容
            const formData = new FormData();
            formData.append("file", files[0]);
            formData.append("cloudPath", "editor/");
            $api.common.uploadImage(formData).then(res => {
                insertImage({
                    url: res.data.tempFileURL,
                    desc: files[0].name,
                    width: "auto",
                    height: "auto"
                });
                editorParams.imageFileIds.push(res.data.fileID);
            });
        };

        // 取消编辑
        const cancelEditor = () => {
            if (store.state.curWritingArticleId) {
                router.push({ path: "/note" });
            } else {
                router.push({ path: "/home" });
            }
            store.commit("setCurWritingArticleId", null);
        };

        //保存编辑
        const saveEdit = flag => {
            if (!editorParams.title) {
                message.error("标题不能为空");
                return;
            }
            let params = {
                id: null,
                title: editorParams.title,
                content: editorParams.content,
                html: editorParams.html,
                author: store.state.userInfo.nickname,
                imageFileIds: editorParams.imageFileIds,
                tags: editorParams.tags
            };
            if (store.state.curWritingArticleId) {
                params.id = store.state.curWritingArticleId;
                updateArticle(params, flag);
            } else {
                addArticle(params, flag);
            }
        };

        // 更新文章
        const updateArticle = (params, flag) => {
            $api.article.updateArticle(params).then(() => {
                message.success("更新成功");
                if (flag) {
                    cancelEditor();
                }
            });
        };

        // 新增文章
        const addArticle = (params, flag) => {
            $api.article.addArticle(params).then(res => {
                store.commit("setCurWritingArticleId", res.data);
                message.success("新增成功");
                if (flag) {
                    cancelEditor();
                }
            });
        };

        // 根据id获取文章
        const getArticle = () => {
            $api.article.getArticle({ id: store.state.curWritingArticleId }).then(res => {
                editorParams.title = res.data.title;
                editorParams.content = res.data.content;
                editorParams.html = res.data.html;
                editorParams.imageFileIds = res.data.imageFileIds;
                editorParams.tags = res.data.tags;
                store.commit("setCurWritingArticleId", res.data.id);
            });
        };

        watchEffect(() => {
            //监听由编辑跳转到新增
            if (store.state.curWritingArticleId === null) {
                editorParams.title = null;
                editorParams.content = "";
                editorParams.html = null;
                editorParams.imageFileIds = [];
            }
        });

        onMounted(() => {
            if (store.state.curWritingArticleId) {
                getArticle();
            }
            // 每5分钟自动保存一次
            autoSaveTimer = setInterval(() => {
                if (editorParams.title) {
                    saveEdit(false);
                }
            }, 5 * 60 * 1000);
        });

        onUnmounted(() => {
            if (autoSaveTimer) {
                clearInterval(autoSaveTimer);
            }
        });

        return {
            saveEdit,
            cancelEditor,
            editorParams,
            mdChange,
            handleUploadImage,
            handleCopyCodeSuccess
        };
    }
};
</script>

<style lang="scss">
.editor-wrapper {
    width: 100%;
    height: 100%;
    overflow: auto;

    .editor-content {
        display: flex;
        width: 1136px;
        margin: 16px auto;
        flex-direction: column;
        box-shadow: 0 1px 8px 0 rgba(0, 0, 0, 0.1);
        padding: 16px;
        min-height: calc(100% - 32px);

        .editor-field {
            margin-top: 16px;
            display: flex;
            align-items: center;

            &:first-of-type {
                margin-top: 0;
            }

            .title {
                margin-right: 16px;
                width: 60px;
            }

            .text {
                flex: 1;
            }

            &.editor-md-field {
                flex: 1;
                min-height: 400px;
                align-items: flex-start;
                height: 0;
                width: 100%;

                .content {
                    border: 1px solid #ececec;
                    align-self: stretch;
                    flex: 1;

                    .md-editor {
                        width: 100%;
                        height: 100%;
                    }
                }
            }
        }

        .btns {
            margin-top: 16px;
            display: flex;
            justify-content: flex-end;
        }
    }
}
</style>
